{"code": "import json
import re

# Load the UC patents data
uc_file = locals()['var_functions.query_db:42']
with open(uc_file, 'r') as f:
    uc_data = json.load(f)

# Step 1: Extract UC publication numbers and their CPCs
uc_pub_map = {}  # publication_number -> primary CPC codes
for record in uc_data:
    patents_info = record.get('Patents_info', '')
    cpc_data = record.get('cpc', '')

    # Extract publication number
    pub_match = re.search(r'([A-Z]{2}-\d+-[A-Z]\d+)', patents_info)
    if pub_match:
        pub_num = pub_match.group(1)

        # Parse CPC to get primary codes (inventive=true or first=true)
        primary_cpcs = []
        if cpc_data:
            try:
                cpc_list = json.loads(cpc_data)
                for cpc_item in cpc_list:
                    if cpc_item.get('inventive') or cpc_item.get('first'):
                        code = cpc_item.get('code')
                        if code:
                            primary_cpcs.append(code)
            except:
                pass

        uc_pub_map[pub_num] = list(set(primary_cpcs))

result = {
    'uc_patents_found': len(uc_data),
    'uc_publication_numbers': len(uc_pub_map),
    'sample_mapping': {k: uc_pub_map[k] for k in list(uc_pub_map.keys())[:3]}
}

print('__RESULT__:')
print(json.dumps(result))"}

{"code": "import json
import re

# Load UC patents data to get publication numbers and their CPCs
uc_file = locals()['var_functions.query_db:42']
with open(uc_file, 'r') as f:
    uc_data = json.load(f)

# Build UC publication number -> CPC mapping
uc_cpc_map = {}
uc_pub_numbers = set()

for record in uc_data:
    patents_info = record.get('Patents_info', '')
    cpc_data = record.get('cpc', '')

    # Extract publication number
    pub_match = re.search(r'([A-Z]{2}-\d+-[A-Z]\d+)', patents_info)
    if pub_match:
        pub_num = pub_match.group(1)
        uc_pub_numbers.add(pub_num)

        # Get primary CPC codes
        primary_cpcs = []
        if cpc_data:
            try:
                cpc_list = json.loads(cpc_data)
                for cpc_item in cpc_list:
                    if cpc_item.get('inventive') or cpc_item.get('first'):
                        code = cpc_item.get('code')
                        if code:
                            primary_cpcs.append(code)
            except:
                pass

        uc_cpc_map[pub_num] = list(set(primary_cpcs))

# Save UC pub numbers and CPC map for next step
result = {
    'uc_publication_numbers': list(uc_pub_numbers),
    'uc_cpc_map': uc_cpc_map,
    'total_uc_pubs': len(uc_pub_numbers)
}

print('__RESULT__:')
print(json.dumps(result))"}

{"code": "import json
import re

# Load UC publication numbers from previous analysis
uc_data = locals()['var_functions.query_db:46']
uc_pub_numbers = set(uc_data['uc_publication_numbers'])

# Load sample patent data to find citations
data_file = locals()['var_functions.query_db:48']
with open(data_file, 'r') as f:
    patents_data = json.load(f)

# Find patents that cite UC patents and get their assignees
citing_patents = []  # List of (citing_patent_info, cited_uc_patent, citing_assignee)
uc_citation_map = {}  # cited_uc_patent -> list of citing patents with assignees

for record in patents_data:
    patents_info = record.get('Patents_info', '')
    citation_data = record.get('citation', '')

    if citation_data:
        try:
            citations = json.loads(citation_data)
            # Check if any citation is a UC patent
            for citation in citations:
                pub_num = citation.get('publication_number', '')
                if pub_num in uc_pub_numbers:
                    # This patent cites a UC patent
                    # Extract assignee from Patents_info
                    assignee_match = re.search(r'^([A-Z][^,]+) holds|^([A-Z][^,]+) is|^Application [^,]+ from [^,]+, (owned by|assigned to|belonging to) ([A-Z][^,\.]+)', patents_info)

                    if assignee_match:
                        # Get the first non-None group
                        assignee = next((g for g in assignee_match.groups() if g), '')
                        if assignee:
                            # Clean up the assignee name
                            assignee = assignee.strip()
                            # Skip if it's UNIV CALIFORNIA
                            if 'UNIV CALIFORNIA' not in assignee.upper() and 'UNIVERSITY OF CALIFORNIA' not in assignee.upper():
                                citing_patents.append({
                                    'citing_patent': patents_info,
                                    'cited_uc_patent': pub_num,
                                    'citing_assignee': assignee
                                })

                                if pub_num not in uc_citation_map:
                                    uc_citation_map[pub_num] = []
                                uc_citation_map[pub_num].append(assignee)
        except:
            pass

# Get unique assignees and their citation counts
assignee_citations = {}
for item in citing_patents:
    assignee = item['citing_assignee']
    if assignee not in assignee_citations:
        assignee_citations[assignee] = set()
    assignee_citations[assignee].add(item['cited_uc_patent'])

result = {
    'total_citing_patents': len(citing_patents),
    'unique_citing_assignees': len(assignee_citations),
    'sample_citations': citing_patents[:5],
    'uc_citation_map_sample': {k: uc_citation_map[k] for k in list(uc_citation_map.keys())[:3]},
    'assignee_citation_summary': {k: len(v) for k, v in list(assignee_citations.items())[:10]}
}

print('__RESULT__:')
print(json.dumps(result))"}

{"code": "import json
import re

# Load UC publication numbers from earlier analysis (using key from execute_python result)
uc_cpc_data = locals()['var_functions.query_db:46']
uc_pub_numbers = set(uc_cpc_data['uc_publication_numbers'])

# Load sample patent data to find citations
data_file = locals()['var_functions.query_db:48']
with open(data_file, 'r') as f:
    patents_data = json.load(f)

# Find patents that cite UC patents and get their assignees
citing_assignees_map = {}  # assignee -> set of UC patents they cite
uc_citation_map = {}  # cited_uc_patent -> list of citing assignees

for record in patents_data:
    patents_info = record.get('Patents_info', '')
    citation_data = record.get('citation', '')

    if citation_data:
        try:
            citations = json.loads(citation_data)
            # Check if any citation is a UC patent
            for citation in citations:
                pub_num = citation.get('publication_number', '')
                if pub_num in uc_pub_numbers:
                    # This patent cites a UC patent - extract assignee
                    assignee_match = re.search(r'^([A-Z][^,]+?) holds|^([A-Z][^,]+?) is|^In [A-Z]{2}, the (?:application|patent filing) [^,]+ (?:is assigned to|owned by|belongs to) ([A-Z][^,\.]+)', patents_info)

                    if assignee_match:
                        # Get the first matching group
                        assignee = next((g for g in assignee_match.groups() if g), '').strip()

                        # Skip UNIV CALIFORNIA
                        if assignee and 'UNIV CALIFORNIA' not in assignee.upper() and 'UNIVERSITY OF CALIFORNIA' not in assignee.upper():
                            # Add to assignee map
                            if assignee not in citing_assignees_map:
                                citing_assignees_map[assignee] = set()
                            citing_assignees_map[assignee].add(pub_num)

                            # Add to UC citation map
                            if pub_num not in uc_citation_map:
                                uc_citation_map[pub_num] = []
                            uc_citation_map[pub_num].append(assignee)
        except:
            pass

# Count citations per assignee
assignee_citation_counts = {assignee: len(pats) for assignee, pats in citing_assignees_map.items()}

result = {
    'total_citations_found': sum(len(v) for v in uc_citation_map.values()),
    'unique_citing_assignees': len(citing_assignees_map),
    'top_citing_assignees': dict(sorted(assignee_citation_counts.items(), key=lambda x: x[1], reverse=True)[:20]),
    'uc_citation_map_sample': {k: uc_citation_map[k][:5] for k in list(uc_citation_map.keys())[:3]}
}

print('__RESULT__:')
print(json.dumps(result))"}

